var argv = require('optimist')
	.describe('group', 'Group to address')
	.default('group', 1)
	.alias('g', 'group')
	.describe('channel', 'Channel to address')
	.default('channel', 1)
	.alias('c', 'channel')
	.describe('property', 'Property to address')
	.alias('p', 'property')
	.describe('output', 'Set outputs.')
	.alias('o', 'output')
	.describe('device', 'Select device type.')
	.default('device', 'usb:CLASS_AN2010')
	.alias('d', 'device')
	.argv;

var vita = require('..');
var vita = vita.open(argv.device);

vita.setProperty(argv.group, argv.channel, 11, 1, function(err) {
	if (err) {
		console.log("\tError: " + err);
		vita.close();
	} else {
		//vita.close();
	}
});

